import React, { useState } from 'react';
import { useHistory } from "react-router-dom";

import {Table} from 'react-bootstrap';

import PaginationList from './PaginationList'

import { useDispatch } from 'react-redux'

import './SelectMenu.css'


const Select = ({itemList, pagesQty, itemsPerPage, dispachType, itemType}) => {

    // State da página atual
    const [actualPage, setActualPage] = useState(1)

    const history = useHistory()

    // Setando o Redux
    const dispach = useDispatch()

    //Adiciona no Redux o item selecionado
    const selectItem = (selectedItem) => {
        dispach({ type: dispachType, title: selectedItem })
    }

    return (
        <>
            <Table responsive>
                
                <tbody>
                    {
                        itemList.slice( ((itemsPerPage*actualPage)-itemsPerPage), ((itemsPerPage*actualPage)) ).map((item, index) => {
                            let field = item.NO_CINE_ROTULO
                            if(itemType === 'IES'){
                                
                                field = `${item.NO_IES} ${item.SG_IES ? `(${item.SG_IES})`:''}`
                            }
                            return(
                                <tr key={item.NO_CINE_ROTULO + index}>
                                    <td className='menuItemColumn' onClick={() => {
                                        selectItem(item)
                                        history.push('/dashboard/')
                                    }}>
                                        <div className='select'>Selecionar</div>
                                        <h5>
                                            {field}
                                        </h5>
                                        
                                    </td>
                                </tr>
                            )
                            
                        })
                    }
                </tbody>
            </Table>
            <div className='pagination'>
                <PaginationList
                    actualPage={actualPage}
                    setActualPage={setActualPage}
                    pagesQty={pagesQty}
                />
            </div>
            
        </>
        

        

    )
}


export default Select;