import React, { useState } from 'react'
import {Row, Col, Card, Form} from 'react-bootstrap';


import Aux from "../hoc/_Aux";
import Redirecionar from './Redirecionar'
import Select from './Select'

import { useDispatch } from 'react-redux'

const List = ({pageTitle, cardTitle, placeholder, data, dataFiltered, filterDispach, selectDispach, itemsPerPage, itemType='curso' }) => {

    const dispach = useDispatch()

    // Estado local
    const [pagesQty, setPagesQty] = useState(Math.ceil(data.length / itemsPerPage))

    // Pesquisa dentro dos dados
    const searchByData = (e) => {
   
        const searchString = e.target.value
        let newList = []
    
        if(searchString === '')
            return false
    
        data.filter((item) => {

            

            if(itemType === 'IES' ){

                if(!item.SG_IES)
                    item = {...item, SG_IES:''}

                if( item.NO_IES.toLowerCase().includes(searchString.toLowerCase()) || item.SG_IES.toLowerCase().includes(searchString.toLowerCase()) ){
                    newList.push(item)
    
                    return true
                }
               
                
            }

            if( itemType==='curso' && item.NO_CINE_ROTULO.toLowerCase().includes(searchString.toLowerCase())){
    
                newList.push(item)
    
                return true
            }
    
            return false
        })
    
        
        return newList
    }

    // Trata o filtro de cursos
    const filterData = (e) => { 
                                
        const dataFiltered = searchByData(e)
        
        dispach({ type: filterDispach, filtered: dataFiltered }) 

        if(dataFiltered)
            setPagesQty( Math.ceil(dataFiltered.length / itemsPerPage))
        else
            setPagesQty( Math.ceil(data.length / itemsPerPage))
    }

    return (
        <Aux>
            <Redirecionar/>
            <Row>
                <Col>
                    <h2>{pageTitle}</h2>
                    <Card>
                        <Card.Header>
                            {cardTitle}
                        </Card.Header>
                        <Card.Body>
                            <Form.Control type="text" placeholder={placeholder} onChange={filterData}/>
                            <Select
                                itemList={dataFiltered === false ? data:dataFiltered}
                                pagesQty={pagesQty}
                                itemsPerPage={itemsPerPage}
                                dispachType={selectDispach}
                                itemType={itemType}
                            />
                        </Card.Body>
                    </Card>
                </Col>
            </Row>
        </Aux>
    )
}

export default List